// COMPLETE, COMPILABLE C code
// Uses correct I/O
// Handles all T test cases
#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        if (n <= 3) {
            printf("-1\n");
        } else {
            printf("%d\n", n - 1);
            for (int i = 1; i < n; i++) {
                printf("%d %d\n", i, i + 1);
            }
            printf("1\n");
        }
    }
    return 0;
}

